function inclusionsHtml(labels, drinkChoice) {
  const baseLine = '<span class="check">✓</span> Майхан кемп · Өглөөний цай · Өдөр болон оройн хоол<br>' +
                   '<span class="check">✓</span> Тайз, хөгжмийн үндсэн тохижилт · Үндсэн гэрэлтүүлэг';
  if (!labels || !labels.length) return baseLine;
  const augmented = labels.map(l => {
    if (l === 'Welcome drink' && drinkChoice) {
      const map = { lemon_basil:'Lemon Basil', iced_tea:'Iced Tea', berry:'Berry', sparkling:'Sparkling' };
      return `Welcome drink (${map[drinkChoice] || drinkChoice})`;
    }
    return l;
  });
  const rows = [];
  for (let i = 0; i < augmented.length; i += 3) rows.push(augmented.slice(i, i + 3).join(' · '));
  return baseLine + '<br>' + rows.map(r => `<span class="check">✓</span> ${r}`).join('<br>');
}

