};

function addonRowsHtml(items) {
  const paid = items.filter(a => !a.tier_included && (a.price || a.unit_price));
  if (!paid.length) return '';
  let html = '<tr class="section"><td colspan="4">НЭМЭЛТ ҮЙЛЧИЛГЭЭ</td></tr>';
  paid.forEach(a => {
    const meta = ADDON_LABEL[a.code] || [a.name || a.code, ''];
    let name = meta[0]; let desc = meta[1] || '';
    let qty = a.quantity || 1; let unit = a.unit_price || 0; let total = a.price || 0;
    if (a.code === 'dj_service') { desc = `${a.start_time||''}–${a.end_time||''} · ${a.duration||''} цаг`; qty = 1; unit = total; }
    if (a.code === 'bartender_service') { desc = `3 цаг · ${a.bartender_count || 1} ажилтан`; qty = a.bartender_count || 1; unit = 500000; }
    if (!unit && qty) unit = total / qty;
    html += `<tr class="line"><td><div class="name">${name}</div>${desc?`<div class="desc">${desc}</div>`:''}</td><td class="qty">${fmt(qty)}</td><td class="unit">${fmt(Math.round(unit))}</td><td class="amt">${fmt(total)}</td></tr>`;
  });
  return html;
}

function shuttleRowsHtml(label, unit, count, subtotal) {
  if (subtotal <= 0) return '';
  const cleanLabel = label.replace(/\s—.*$/, '').replace(/\s-.*$/, '');
  return `<tr class="section"><td colspan="4">ТЭЭВРИЙН ҮЙЛЧИЛГЭЭ</td></tr><tr class="line"><td><div class="name">${cleanLabel}</div><div class="desc">45 хүний автобус · УБ ↔ NOMAAD кемп</div></td><td class="qty">${count}</td><td class="unit">${fmt(unit)}</td><td class="amt">${fmt(subtotal)}</td></tr>`;
}

function valueAnchorHtml(va) {
  if (!va || !va.lines || va.savings <= 0) return '';
  const rows = va.lines.map(l => `<tr><td class="lbl">${l.label}</td><td class="v">${fmt(l.amount)}</td></tr>`).join('');
  return `<div class="anchor"><div class="anchor__head"><div class="anchor__title">★ ҮНЭ ЦЭНИЙН ХАРЬЦУУЛАЛТ</div><div class="anchor__sub">${tier} багцын давуу тал</div></div><table>${rows}<tr class="standalone"><td class="lbl">Тус тусдаа авбал нийт</td><td class="v">${fmt(va.standalone_total)} ₮</td></tr><tr class="package"><td class="lbl">${tier} багцаар авбал</td><td class="v">${fmt(va.package_total)} ₮</td></tr><tr class="savings"><td class="lbl">★ Хэмнэлт</td><td class="v">−${fmt(va.savings)} ₮ · ${va.savings_pct}%</td></tr></table></div>`;
}

