const internalSummary = `🆕 Шинэ үнийн санал ${quoteNumber}\nКомпани: ${company}${customerTaxId !== '—' ? ' (РД ' + customerTaxId + ')' : ''}\nХолбоо: ${contactName} · ${phone} · ${email || '—'}\nКемп: ${camp} · ${tier} · ${guests} хүн · ${durationLabel}\nОгноо: ${fmtDateOnly(startDt)} → ${fmtDateOnly(endDt)}\nБагц: ${fmt(tierSubtotal)}₮\nНэмэлт: ${fmt(addonsSubtotal)}₮ (${paidAddonCount} төрөл)\nТээвэр: ${fmt(shuttleSubtotal)}₮${busCount > 1 ? ' (' + busCount + ' автобус)' : ''}\nНИЙТ: ${fmt(grandTotal)}₮\nУрьдчилгаа 30%: ${fmt(deposit30)}₮${str(p.notes) ? '\n\nТэмдэглэл: ' + str(p.notes) : ''}`;

return { json: {
